 60→  deps: ChatToolDeps & { pmAgentModel: any };
 61→  context: ChatToolExecutionContext;
 62→  intent: "plan_work" | "check_status" | "organize" | "track_dependencies";
 63→  conversationContext: string;
 64→  project?: string;
 65→};
