 75→  const system = await buildPmSystemPrompt({
 76→    surreal: input.deps.surreal,
 77→    workspaceRecord: input.context.workspaceRecord,
 78→  });
 79→
 80→  const agent = new ToolLoopAgent({
 81→    id: "pm-agent",
 82→    model: input.deps.pmAgentModel,
 83→    instructions: system,
 84→    tools: createPmTools(input.deps),
 85→    output: Output.object({ schema: pmAgentResultSchema }),
 86→    experimental_context: { ...input.context, actor: "pm_agent" as const },
 87→    stopWhen: stepCountIs(6),
 88→  });
 89→
 90→  const result = await agent.generate({
 91→    prompt: [
 92→      "You are handling a PM request.",
 93→      `Intent: ${input.intent}`,
 94→      input.project ? `Project hint: ${input.project}` : "Project hint: not provided",
 95→      INTENT_INSTRUCTIONS[input.intent],
 96→      "Context:",
 97→      input.conversationContext,
 98→    ].join("\n"),
 99→  });
100→
101→  if (!result.output) {
102→    throw new Error("pm agent did not produce structured output");
103→  }
104→
105→  const extracted_entities: ExtractedEntity[] = [];
106→  const extracted_relationships: ExtractedRelationship[] = [];
107→
108→  for (const step of result.steps) {
109→    for (const toolResult of step.toolResults) {
110→      const res = toolResult.output as Record<string, unknown> | undefined;
111→      if (res) {
112→        if (Array.isArray(res.extracted_entities)) {
113→          extracted_entities.push(...(res.extracted_entities as ExtractedEntity[]));
114→        }
115→        if (Array.isArray(res.extracted_relationships)) {
116→          extracted_relationships.push(...(res.extracted_relationships as ExtractedRelationship[]));
117→        }
118→      }
119→    }
120→  }
121→
