 18→
 19→type ChatRequestBody = {
 20→  messages: UIMessage[];
 21→  workspaceId: string;
 22→  conversationId?: string;
 23→  onboardingAction?: OnboardingAction;
 24→  discussEntityId?: string;
 25→};
 26→
 27→const onboardingActions = new Set(["finalize_onboarding", "continue_onboarding"]);
 28→
 29→export function createChatRouteHandler(deps: ServerDependencies) {
 30→  return (request: Request) => handleChatRequest(deps, request);
 31→}
 32→
 33→async function handleChatRequest(deps: ServerDependencies, request: Request): Promise<Response> {
 34→  const startedAt = performance.now();
 35→
 36→  let body: ChatRequestBody;
 37→  try {
 38→    body = await request.json() as ChatRequestBody;
 39→  } catch {
 40→    return jsonError("Request body must be valid JSON", 400);
 41→  }
 42→
 43→  if (!body.workspaceId || body.workspaceId.trim().length === 0) {
 44→    return jsonError("workspaceId is required", 400);
 45→  }
 46→  if (!Array.isArray(body.messages) || body.messages.length === 0) {
 47→    return jsonError("messages array is required", 400);
 48→  }
 49→  if (body.onboardingAction && !onboardingActions.has(body.onboardingAction)) {
 50→    return jsonError("onboardingAction must be finalize_onboarding or continue_onboarding", 400);
 51→  }
 52→
 53→  const lastMessage = body.messages[body.messages.length - 1];
 54→  if (lastMessage.role !== "user") {
 55→    return jsonError("last message must be a user message", 400);
 56→  }
 57→
 58→  const userText = extractTextFromUIMessage(lastMessage);
 59→  if (userText.trim().length === 0) {
 60→    return jsonError("user message text is required", 400);
 61→  }
 62→
 63→  const conversationId = body.conversationId ?? randomUUID();
 64→  const messageId = randomUUID();
 65→  const userMessageRecord = new RecordId("message", randomUUID());
 66→
 67→  let workspaceRecord: RecordId<"workspace", string>;
