        parts.push({
          type: "tool-invoke_pm_agent",
          state: "output-available",
          output: { trace },
        } as any);
      }
    }
    return { id: m.id, role: m.role, parts, createdAt: new Date(m.createdAt) };
  });
}
```

### 7. Render collapsible (`app/src/client/routes/chat-page.tsx`)

In the tool-part rendering branch, add handling for `invoke_pm_agent`:

```tsx
