const content = FILE_CONTENT;
const lines = content.split('\n');

// Find invoke_pm_agent references
const pmAgentRefs = [];
const sseEmissionPoints = [];
const extractionPersistence = [];

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  if (line.includes('invoke_pm_agent') || line.includes('runPmAgent')) {
    pmAgentRefs.push(`Line ${i + 1}: ${line.trim()}`);
  }
  if (line.includes('emit') || line.includes('SSE') || line.includes('sseRegistry')) {
    sseEmissionPoints.push(`Line ${i + 1}: ${line.trim()}`);
  }
  if (line.includes('extraction') && (line.includes('persist') || line.includes('create'))) {
    extractionPersistence.push(`Line ${i + 1}: ${line.trim()}`);
  }
}

console.log('=== PM Agent Invocation References ===');
pmAgentRefs.slice(0, 20).forEach(ref => console.log(ref));

console.log('\n=== SSE Emission Points ===');
sseEmissionPoints.slice(0, 20).forEach(ref => console.log(ref));

console.log('\n=== Extraction Persistence References ===');
extractionPersistence.slice(0, 20).forEach(ref => console.log(ref));

console.log('\n=== File Structure Overview ===');
console.log(`Total lines: ${lines.length}`);
console.log(`Export statements: ${lines.filter(l => l.startsWith('export')).length}`);
console.log(`Async functions: ${lines.filter(l => l.includes('async ')).length}`);

