299→function sanitizeAssistantSuggestions(suggestions: string[], limit: number): string[] {
300→  return [...new Set(suggestions.map((value) => value.trim()))]
301→    .filter((value) => value.length > 0 && value.length <= 140)
302→    .slice(0, limit);
303→}
