  1→import { stepCountIs, streamText, type ModelMessage } from "ai";
  2→import { RecordId, Surreal } from "surrealdb";
  3→import type { ExtractedEntity, ExtractedRelationship, OnboardingState } from "../../shared/contracts";
  4→import { logInfo, logError } from "../http/observability";
  5→import { buildChatContext, buildSystemPrompt, type ChatContext } from "./context";
  6→import { createChatAgentTools } from "./tools";
  7→
  8→type ConversationMessage = {
  9→  role: "user" | "assistant";
 10→  text: string;
 11→};
 12→
 13→type CollectedEntity = ExtractedEntity;
 14→type CollectedRelationship = ExtractedRelationship;
 15→
 16→export type ChatAgentResult = {
 17→  text: string;
 18→  collectedEntities: CollectedEntity[];
 19→  collectedRelationships: CollectedRelationship[];
 20→  toolCalls: Array<{ name: string; args: Record<string, unknown> }>;
 21→};
 22→
 23→export async function runChatAgent(input: {
 24→  surreal: Surreal;
 25→  model: any;
 26→  pmAgentModel: any;
 27→  analyticsAgentModel: any;
 28→  analyticsSurreal: Surreal;
 29→  embeddingModel: any;
 30→  embeddingDimension: number;
 31→  extractionModelId: string;
 32→  extractionModel: any;
 33→  extractionStoreThreshold: number;
 34→  conversationRecord: RecordId<"conversation", string>;
 35→  workspaceRecord: RecordId<"workspace", string>;
 36→  currentMessageRecord: RecordId<"message", string>;
 37→  latestUserText: string;
 38→  workspaceOwnerRecord?: RecordId<"person", string>;
 39→  personRecord: RecordId<"person", string>;
 40→  userMessageEmbedding?: number[];
 41→  inheritedEntityIds?: RecordId[];
 42→  discussesRecord?: RecordId;
 43→  messages: ConversationMessage[];
 44→  isOnboarding?: boolean;
 45→  onboardingState?: OnboardingState;
 46→  workspaceDescription?: string;
 47→  onToken: (token: string) => Promise<void> | void;
 48→  onReasoning?: (token: string) => Promise<void> | void;
 49→}): Promise<ChatAgentResult> {
 50→  const context = await buildChatContext({
 51→    surreal: input.surreal,
 52→    conversationRecord: input.conversationRecord,
 53→    workspaceRecord: input.workspaceRecord,
 54→    ...(input.workspaceDescription ? { workspaceDescription: input.workspaceDescription } : {}),
 55→    ...(input.userMessageEmbedding ? { userMessageEmbedding: input.userMessageEmbedding } : {}),
 56→    ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 57→      ? { inheritedEntityIds: input.inheritedEntityIds }
 58→      : {}),
 59→    ...(input.discussesRecord ? { discussesRecord: input.discussesRecord } : {}),
 60→  });
 61→
 62→  const system = buildSystemPrompt(context, {
 63→    isOnboarding: input.isOnboarding,
 64→    onboardingState: input.onboardingState,
 65→  });
 66→
 67→  const modelMessages: ModelMessage[] = input.messages.map((message) => ({
 68→    role: message.role,
 69→    content: message.text,
 70→  }));
 71→
 72→  const result = streamText({
 73→    model: input.model,
 74→    system,
 75→    messages: modelMessages,
 76→    tools: createChatAgentTools({
 77→      surreal: input.surreal,
 78→      pmAgentModel: input.pmAgentModel,
 79→      analyticsAgentModel: input.analyticsAgentModel,
 80→      analyticsSurreal: input.analyticsSurreal,
 81→      embeddingModel: input.embeddingModel,
 82→      embeddingDimension: input.embeddingDimension,
 83→      extractionModelId: input.extractionModelId,
 84→      extractionModel: input.extractionModel,
 85→      extractionStoreThreshold: input.extractionStoreThreshold,
 86→    }),
 87→    experimental_context: {
 88→      actor: "chat_agent",
 89→      humanPresent: true,
 90→      workspaceRecord: input.workspaceRecord,
 91→      conversationRecord: input.conversationRecord,
 92→      currentMessageRecord: input.currentMessageRecord,
 93→      latestUserText: input.latestUserText,
 94→      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
 95→      personRecord: input.personRecord,
 96→    },
 97→    stopWhen: stepCountIs(5),
 98→  });
 99→
100→  let text = "";
101→  const collectedEntities: CollectedEntity[] = [];
102→  const collectedRelationships: CollectedRelationship[] = [];
103→  const toolCalls: Array<{ name: string; args: Record<string, unknown> }> = [];
104→
105→  for await (const part of result.fullStream) {
106→    if (part.type === "reasoning-delta") {
107→      await input.onReasoning?.(part.text);
108→      continue;
109→    }
110→
111→    if (part.type === "text-delta") {
112→      text = `${text}${part.text}`;
113→      await input.onToken(part.text);
114→      continue;
115→    }
116→
117→    if (part.type === "tool-call") {
118→      logInfo("chat.agent.tool_call", "Chat agent invoked tool", part);
119→      toolCalls.push({ name: part.toolName, args: (part as any).input as Record<string, unknown> });
120→    }
121→
122→    if (part.type === "tool-result") {
123→      logInfo("chat.agent.tool_result", "Chat agent tool returned", part);
124→      const toolResult = part.output as Record<string, unknown> | undefined;
125→      if (toolResult) {
126→        if (Array.isArray(toolResult.extracted_entities)) {
127→          collectedEntities.push(...(toolResult.extracted_entities as CollectedEntity[]));
128→        }
129→        if (Array.isArray(toolResult.extracted_relationships)) {
130→          collectedRelationships.push(...(toolResult.extracted_relationships as CollectedRelationship[]));
131→        }
132→      }
133→    }
134→
135→    if (part.type === "error") {
136→      logError("chat.agent.stream_error", "Chat agent stream error", part.error, {});
137→    }
138→  }
139→
140→  if (text.trim().length === 0) {
141→    text = await result.text;
142→  }
143→
144→  // Post-process: inject entity:// links for entity names mentioned in the response.
145→  const linked = injectEntityLinks(text, context);
146→  if (linked !== text) {
147→    // Re-send the full linked text as a replacement.
148→    // The SSE stream already sent raw text; the persisted version will have links.
149→    text = linked;
150→  }
151→
152→  return {
153→    text: text.trim(),
154→    collectedEntities,
155→    collectedRelationships,
156→    toolCalls,
157→  };
158→}
159→
160→export const runGraphAwareChat = runChatAgent;
161→
162→type KnownEntity = { entityId: string; kind: string; name: string };
163→
164→/**
165→ * Replace entity name mentions in response text with markdown links:
166→ *   "Model for Extraction Pipeline" → "[Model for Extraction Pipeline](entity://decision:uuid)"
167→ *
168→ * Matches longest names first to avoid partial replacement.
169→ * Only replaces the first occurrence of each entity name.
170→ */
171→function injectEntityLinks(text: string, context: ChatContext): string {
172→  const entities: KnownEntity[] = [];
173→
174→  for (const project of context.workspaceSummary.projects) {
175→    entities.push({ entityId: `project:${project.id}`, kind: "project", name: project.name });
176→  }
177→  for (const decision of context.workspaceSummary.recentDecisions) {
178→    entities.push({ entityId: `decision:${decision.id}`, kind: "decision", name: decision.name });
179→  }
180→  for (const question of context.workspaceSummary.openQuestions) {
181→    entities.push({ entityId: `question:${question.id}`, kind: "question", name: question.name });
182→  }
183→
184→  // Sort longest name first so "Agent-Native Business OS" matches before "Agent"
185→  entities.sort((a, b) => b.name.length - a.name.length);
186→
187→  const replaced = new Set<string>();
188→  let result = text;
189→
190→  for (const entity of entities) {
191→    if (entity.name.length < 3) continue;
192→    if (replaced.has(entity.entityId)) continue;
193→
194→    // Case-insensitive match, but only replace the first occurrence.
195→    // Skip if the name is already inside a markdown link.
196→    const idx = result.toLowerCase().indexOf(entity.name.toLowerCase());
197→    if (idx === -1) continue;
198→
199→    // Check if already inside a markdown link: [...](...)
200→    const before = result.slice(0, idx);
201→    if (before.lastIndexOf("[") > before.lastIndexOf("]")) continue;
202→
203→    const matched = result.slice(idx, idx + entity.name.length);
204→    const link = `[${matched}](#entity/${entity.entityId})`;
205→    result = `${result.slice(0, idx)}${link}${result.slice(idx + entity.name.length)}`;
206→    replaced.add(entity.entityId);
207→  }
208→
209→  return result;
210→}
