 28→  // Keep a ref to the latest chat handlers so the effect below doesn't
 29→  // depend on unstable function references.
 30→  const chatRef = useRef(chat);
 31→  chatRef.current = chat;
 32→
 33→  // Register sidebar handlers so the shell sidebar can interact with chat
 34→  useEffect(() => {
 35→    setSidebarHandlers({
 36→      activeConversationId: chat.activeConversationId,
 37→      isLoading: chat.isLoading,
 38→      onNewConversation: () => chatRef.current.newConversation(),
 39→      onSelectConversation: (id: string) => chatRef.current.selectConversation(id),
