206→function ChatInput({
207→  onSend,
208→  disabled,
209→  onStop,
210→  isStreaming,
211→}: {
212→  onSend: (text: string) => void;
213→  disabled: boolean;
214→  onStop: () => void;
215→  isStreaming: boolean;
216→}) {
217→  const [input, setInput] = useState("");
218→  const textareaRef = useRef<HTMLTextAreaElement>(null);
219→
220→  function handleSubmit() {
221→    const trimmed = input.trim();
222→    if (!trimmed || disabled) return;
223→    onSend(trimmed);
224→    setInput("");
225→    // Reset textarea height
226→    if (textareaRef.current) {
227→      textareaRef.current.style.height = "auto";
228→    }
229→  }
230→
231→  function handleKeyDown(e: KeyboardEvent<HTMLTextAreaElement>) {
232→    if (e.key === "Enter" && !e.shiftKey) {
233→      e.preventDefault();
234→      handleSubmit();
235→    }
236→  }
237→
238→  // Auto-resize textarea
239→  useEffect(() => {
240→    const textarea = textareaRef.current;
241→    if (!textarea) return;
242→    textarea.style.height = "auto";
243→    textarea.style.height = `${Math.min(textarea.scrollHeight, 200)}px`;
244→  }, [input]);
245→
246→  return (
247→    <div className="chat-input-container">
248→      <textarea
249→        ref={textareaRef}
250→        className="chat-input"
251→        value={input}
252→        onChange={(e) => setInput(e.target.value)}
253→        onKeyDown={handleKeyDown}
254→        placeholder="Discuss tasks, decisions, and questions..."
255→        rows={1}
256→        disabled={disabled && !isStreaming}
257→      />
258→      {isStreaming ? (
259→        <button
260→          type="button"
261→          className="chat-input-btn chat-input-btn--stop"
262→          onClick={onStop}
263→          title="Stop"
264→        >
265→          Stop
266→        </button>
267→      ) : (
268→        <button
269→          type="button"
270→          className="chat-input-btn chat-input-btn--send"
271→          onClick={handleSubmit}
272→          disabled={disabled || input.trim().length === 0}
273→          title="Send"
274→        >
275→          Send
276→        </button>
277→      )}
278→    </div>
279→  );
280→}
