  startedAt: string; // ISO 8601
};

export type SubagentTrace = {
  agentId: string;        // "pm-agent"
  intent: string;         // "plan_work" | "check_status" | etc.
  steps: SubagentToolStep[];
  totalDurationMs: number;
};
```

Extend `WorkspaceBootstrapMessage`:

