4. Switch from `agent.generate()` to `agent.stream()` with callbacks:

```typescript
export async function runPmAgent(input: PmAgentInput): Promise<PmAgentOutput> {
  const system = await buildPmSystemPrompt({ ... });
  const traceSteps: SubagentToolStep[] = [];
  const stepTimers = new Map<string, number>();
  const agentStartedAt = performance.now();

  const agent = new ToolLoopAgent({
    id: "pm-agent",
    model: input.deps.pmAgentModel,
    instructions: system,
    tools: createPmTools(input.deps),
    output: Output.object({ schema: pmAgentResultSchema }),
    experimental_context: { ...input.context, actor: "pm_agent" as const },
    stopWhen: stepCountIs(6),
  });

  const streamResult = await agent.stream({
    prompt: [
      "You are handling a PM request.",
      `Intent: ${input.intent}`,
      input.project ? `Project hint: ${input.project}` : "Project hint: not provided",
      INTENT_INSTRUCTIONS[input.intent],
      "Context:",
      input.conversationContext,
    ].join("\n"),

    experimental_onToolCallStart: ({ toolCall }) => {
      stepTimers.set(toolCall.toolCallId, performance.now());
      input.onToolCallStart?.(toolCall.toolName, toolCall.input);
    },

    experimental_onToolCallFinish: ({ toolCall, ...rest }) => {
      const startTime = stepTimers.get(toolCall.toolCallId) ?? performance.now();
      const nowMs = performance.now();
      const step: SubagentToolStep = {
        toolName: toolCall.toolName,
        args: JSON.stringify(toolCall.input),
        result: JSON.stringify(
          rest.success ? rest.output : { error: String(rest.error) }
        ),
        durationMs: Math.round(nowMs - startTime),
        startedAt: new Date(Date.now() - Math.round(nowMs - startTime)).toISOString(),
      };
      traceSteps.push(step);
      input.onToolCallFinish?.(step);
    },
  });

  // Consume stream to get structured output
  const output = await streamResult.output;
  if (!output) {
    throw new Error("pm agent did not produce structured output");
  }

  // Collect extracted entities/relationships from steps
  const extracted_entities: ExtractedEntity[] = [];
  const extracted_relationships: ExtractedRelationship[] = [];
  const steps = await streamResult.steps;

  for (const step of steps) {
    for (const toolResult of step.toolResults) {
      const res = toolResult.output as Record<string, unknown> | undefined;
      if (res) {
        if (Array.isArray(res.extracted_entities)) {
          extracted_entities.push(...(res.extracted_entities as ExtractedEntity[]));
        }
        if (Array.isArray(res.extracted_relationships)) {
          extracted_relationships.push(...(res.extracted_relationships as ExtractedRelationship[]));
        }
      }
    }
  }

  return {
    ...output,
    extracted_entities,
    extracted_relationships,
    trace: {
      agentId: "pm-agent",
      intent: input.intent,
      steps: traceSteps,
      totalDurationMs: Math.round(performance.now() - agentStartedAt),
    },
  };
}
```

