                  {step.durationMs ? <span className="subagent-trace-duration">{step.durationMs}ms</span> : undefined}
                </summary>
                <pre className="subagent-trace-args">{step.argsJson}</pre>
                <pre className="subagent-trace-result">{step.resultJson}</pre>
              </details>
            );
          })}
        </div>
      </details>
    );
  }
}

