465→
466→  LET $task_rows = SELECT
467→    id,
468→    "task" AS kind,
469→    title AS text,
470→    extraction_confidence AS confidence,
471→    source_message AS sourceMessage,
472→    priority,
473→    created_at
474→  FROM task
475→  WHERE workspace = $workspace
476→    AND extraction_confidence != NONE
477→    AND string::contains(string::lowercase(title), $query)
478→  ORDER BY created_at DESC
479→  LIMIT $safe_limit;
480→
481→  LET $decision_rows = SELECT
482→    id,
483→    "decision" AS kind,
484→    summary AS text,
485→    extraction_confidence AS confidence,
486→    source_message AS sourceMessage,
487→    priority,
488→    created_at
489→  FROM decision
490→  WHERE workspace = $workspace
491→    AND extraction_confidence != NONE
492→    AND string::contains(string::lowercase(summary), $query)
493→  ORDER BY created_at DESC
494→  LIMIT $safe_limit;
495→
496→  LET $question_rows = SELECT
497→    id,
498→    "question" AS kind,
499→    text AS text,
500→    extraction_confidence AS confidence,
501→    source_message AS sourceMessage,
502→    priority,
503→    created_at
504→  FROM question
505→  WHERE workspace = $workspace
506→    AND extraction_confidence != NONE
507→    AND string::contains(string::lowercase(text), $query)
508→  ORDER BY created_at DESC
509→  LIMIT $safe_limit;
510→
511→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
